} else if (['/i', '/id'].includes(text) && (groupId != null)) {
  return [{ json: { cmd: 'get_group_id', replyToken, userId } }];
} else if (['/i', '/id'].includes(text)) {
  return [{ json: { cmd: 'get_id', replyToken, userId } }];
} else if (['/help', '/幫助', "/說明", "/指令"].includes(text)) {
  return [{ json: { cmd: 'help', replyToken, userId } }];
} else if (['PLEASE_RESEND_ALL_NOTIFYCATION', "PRAN!!!"].includes(text)) {
  return [{ json: { cmd: 'PLEASE_RESEND_ALL_NOTIFYCATION', replyToken, userId } }];
} else if (text.includes('@Asst. 總結') || text.includes('AI總結')) {
  return [{ json: { cmd: 'summarize', replyToken, userId, groupId } }];
}
return [];

