// 取得所有從 Google Sheets 抓到的行 (多行資料會自動變成陣列)
const items = $input.all();

return items.map(item => {
  const row = item.json;

  // 組合訊息格式 📣[{{Date}}] {{Content}}
  // 使用傳統字串相加，避免舊版 n8n 的語法衝突
  const formattedText = "📣[" + (row.Date || "") + "]\n" + (row.Content || "").replace(/\r/g, "");

  return {
    json: {
      // 這裡準備好 LINE Push API 要用的 JSON 結構
      linePayload: {
        "to": row.To,
        "messages": [
          {
            "type": "text",
            "text": formattedText
          }
        ]
      }
    }
  };
});

const allItems = $input.all();
const replyToken = $("Edit Fields").first().json.replyToken;

// --- 1. 設定台灣時間基準點 (校準 UTC+8) ---
const twNowStr = new Date().toLocaleString("en-US", {timeZone: "Asia/Taipei"});
const twNow = new Date(twNowStr);
const currentYear = twNow.getFullYear();
const today = new Date(currentYear, twNow.getMonth(), twNow.getDate()).getTime();

const getTimestamp = (ds) => {
  if (!ds || ds === "空白") return null;
  const d = new Date(ds);
  if (isNaN(d.getTime())) return null;
  return new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime();
};

const formatCleanDate = (dateStr) => {
  if (!dateStr || dateStr === "空白") return "";
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return dateStr;
  const year = d.getFullYear();
  const month = (d.getMonth() + 1).toString().padStart(2, '0');
  const day = d.getDate().toString().padStart(2, '0');
  const weekDays = ["週日", "週一", "週二", "週三", "週四", "週五", "週六"];
  const weekday = weekDays[d.getDay()];
  return (year === currentYear) ? `${month}/${day} (${weekday})` : `${year}/${month}/${day} (${weekday})`;
};

// --- 2. 處理「沒有任務」的情況 ---
if (allItems.length === 0 || (allItems.length === 1 && !allItems[0].json.Content && !allItems[0].json.To_Name)) {
  return [{
    json: {
      replyToken: replyToken,
      flexMessage: {
        "type": "flex",
        "altText": "目前沒有待辦任務",
        "contents": {
          "type": "bubble",
          "size": "mega",
          "header": {
            "type": "box", "layout": "vertical", "paddingAll": "16px", "backgroundColor": "#7EB2D1",
            "contents": [{ "type": "text", "text": "系統狀態", "weight": "bold", "size": "lg", "color": "#ffffff" }]
          },
          "body": {
            "type": "box", "layout": "vertical", "paddingAll": "32px", "spacing": "md", "alignItems": "center",
            "contents": [
              { "type": "text", "text": "☕", "size": "4xl" },
              { "type": "text", "text": "目前沒有待辦任務", "weight": "bold", "size": "md", "color": "#555555" },
              { "type": "text", "text": "您可以暫時放鬆一下，或是檢查篩選條件是否正確。", "size": "xs", "color": "#AAAAAA", "wrap": true, "align": "center" }
            ]
          }
        }
      }
    }
  }];
}

// --- 3. 執行排序邏輯 (有任務時) ---
allItems.sort((a, b) => {
  const dateA = getTimestamp(a.json.Date) || getTimestamp(a.json.Send_Day) || 9999999999999;
  const dateB = getTimestamp(b.json.Date) || getTimestamp(b.json.Send_Day) || 9999999999999;
  const isFutureA = dateA >= today;
  const isFutureB = dateB >= today;
  if (isFutureA && !isFutureB) return -1;
  if (!isFutureA && isFutureB) return 1;
  return dateA - dateB;
});

// 4. 小工具：產生按鈕
const getButtonsFromContent = (content) => {
  const urlRegex = /(https?:\/\/[^\s]+)/g;
  const urls = content.match(urlRegex) || [];
  return urls.map(url => {
    let label = "開啟連結", color = "#888888"; 
    if (url.includes("spreadsheets")) { label = "開啟 Google 試算表"; color = "#4F772D"; }
    else if (url.includes("forms")) { label = "填寫 Google 表單"; color = "#778DA9"; }
    else if (url.includes("document")) { label = "查看 Google 文檔"; color = "#6B9080"; }
    else if (url.includes("canva.com")) { label = "在 Canva 中開啟"; color = "#4895EF"; }
    return {
      "type": "box", "layout": "vertical", "justifyContent": "center", "alignItems": "center",
      "contents": [{ "type": "text", "text": label, "color": color, "size": "sm", "weight": "bold", "align": "center" }],
      "borderWidth": "1px", "borderColor": color, "cornerRadius": "md", "height": "40px", "margin": "sm",
      "action": { "type": "uri", "label": label, "uri": url }
    };
  });
};

// 5. 建立 Flex Message 卡片
const bubbles = allItems.slice(0, 12).map(item => {
  const row = item.json;
  if (!row.To_Name && !row.Content) return null; // 排除空資料

  const toName = row.To_Name || "未知接收者";
  const dateTimestamp = getTimestamp(row.Date);
  const dateDisplay = formatCleanDate(row.Date);
  const sdTimestamp = getTimestamp(row.Send_Day || row['Send Date']);
  const sdDisplay = formatCleanDate(row.Send_Day || row['Send Date']) || "今日";

  let diff = (dateTimestamp !== null) ? Math.round((dateTimestamp - today) / 86400000) : null;
  let dateRowBgColor = "#ffffff", dateTextColor = "#333333", countdownText = "", countdownColor = "#E67E22"; 

  if (diff === 0) { dateRowBgColor = "#FFF3E0"; countdownText = "就是今天"; }
  else if (diff !== null && diff < 0) { dateTextColor = "#BBBBBB"; countdownText = "活動已結束"; countdownColor = "#BBBBBB"; }
  else if (diff !== null && diff > 0) { countdownText = `還剩 ${diff} 天`; }

  let remindLeadText = "";
  if (sdTimestamp !== null) {
    if (dateTimestamp !== null && sdTimestamp > dateTimestamp) {
      const futureDiff = Math.round((sdTimestamp - dateTimestamp) / 86400000);
      remindLeadText = `來自 ${futureDiff} 天後未來人`;
    } else {
      const sdDiff = Math.round((sdTimestamp - today) / 86400000);
      if (sdDiff > 0) remindLeadText = `${sdDiff} 天後提醒`;
      else if (sdDiff === 0) remindLeadText = "今天提醒";
      else remindLeadText = "已發送提醒";
    }
  }

  const buttons = getButtonsFromContent(row.Content || "");
  const cleanContent = (row.Content || "").replace(/(https?:\/\/[^\s]+)/g, "").trim() || "(無任務)";

  const dateRowHorizontalContents = [{ "type": "text", "text": dateDisplay || sdDisplay, "weight": "bold", "size": "md", "color": dateTextColor, "flex": 4 }];
  if (countdownText) { dateRowHorizontalContents.push({ "type": "text", "text": countdownText, "size": "xs", "color": countdownColor, "align": "end", "gravity": "bottom", "flex": 2, "weight": "bold" }); }

  const remindRowHorizontalContents = [{ "type": "text", "text": `⏰${sdDisplay}`, "size": "xs", "color": "#999999", "flex": 4 }];
  if (remindLeadText) { remindRowHorizontalContents.push({ "type": "text", "text": remindLeadText, "size": "xxs", "color": "#BBBBBB", "align": "end", "flex": 3 }); }

  return {
    "type": "bubble", "size": "mega",
    "header": { "type": "box", "layout": "vertical", "paddingAll": "16px", "backgroundColor": "#7EB2D1", "contents": [{ "type": "text", "text": toName, "weight": "bold", "size": "lg", "color": "#ffffff" }] },
    "body": {
      "type": "box", "layout": "vertical", "paddingAll": "0px",
      "action": { "type": "message", "label": "Reply", "text": `📣${dateDisplay || sdDisplay}\n\n${row.Content}`.substring(0, 300) },
      "contents": [
        { "type": "box", "layout": "vertical", "paddingAll": "16px", "backgroundColor": dateRowBgColor, "contents": [{ "type": "box", "layout": "horizontal", "contents": dateRowHorizontalContents }] },
        { "type": "separator", "color": "#F0F0F0" },
        { "type": "box", "layout": "vertical", "paddingAll": "16px", "paddingTop": "12px", "contents": [ { "type": "box", "layout": "horizontal", "contents": remindRowHorizontalContents }, { "type": "text", "text": cleanContent, "size": "md", "color": (diff !== null && diff < 0) ? "#AAAAAA" : "#555555", "wrap": true, "margin": "lg", "weight": "bold", "maxLines": 8, "lineSpacing": "4px" } ] }
      ]
    },
    "footer": buttons.length > 0 ? { "type": "box", "layout": "vertical", "spacing": "xs", "paddingAll": "12px", "contents": buttons } : undefined
  };
}).filter(b => b !== null);

return [{
  json: {
    replyToken: replyToken,
    flexMessage: {
      "type": "flex",
      "altText": "任務提醒清單已更新",
      "contents": { "type": "carousel", "contents": bubbles }
    }
  }
}];

