// 接收觸發參數
const triggerGroupId = $input.first().json?.body?.group_id || '';
const trigger = $input.first().json?.body?.trigger || 'threshold';

// 讀取所有未處理訊息
const allRows = $('讀取所有未處理訊息').all().map(r => r.json);

if (allRows.length === 0) {
  return [{ json: { skip: true, reason: 'no unprocessed messages', groups: [] } }];
}

// 按群組分組
const groupMap = {};
allRows.forEach(r => {
  const gid = r.group_id || 'unknown';
  if (!groupMap[gid]) groupMap[gid] = [];
  groupMap[gid].push(r);
});

// 決定要處理哪些群組
// 手動觸發且沒有指定群組 → 處理所有群組
// 手動觸發且有指定群組 → 只處理該群組
// 閾值觸發 → 只處理指定群組
let groupsToProcess = Object.keys(groupMap);
if (triggerGroupId) {
  groupsToProcess = groupsToProcess.filter(gid => gid === triggerGroupId);
}

if (groupsToProcess.length === 0) {
  return [{ json: { skip: true, reason: 'no matching group', groups: [] } }];
}

// 每個群組產出一筆資料
return groupsToProcess.map(gid => {
  const rows = groupMap[gid];
  const groupName = rows[0].group_name || gid;

  const messages = rows
    .sort((a, b) => (a.created_at || '').localeCompare(b.created_at || ''))
    .map(r => `[${r.created_at}] ${r.sender_name}: ${r.content}`)
    .join('\n');

  const urls = rows
    .filter(r => r.has_url && r.urls)
    .flatMap(r => String(r.urls).split(',').map(u => u.trim()))
    .filter(Boolean);

  return {
    json: {
      skip: false,
      trigger,
      group_id: gid,
      group_name: groupName,
      message_count: rows.length,
      messages,
      urls: [...new Set(urls)]
    }
  };
});

const results = [];

for (const item of $input.all()) {
  const data = item.json;
  if (!data.todos || data.todos.length === 0) continue;

  for (const t of data.todos) {
