        },
        {
          role: 'user',
          content: prompt
        }
      ]
    }
  };
});

const results = [];
const kimiResponses = $input.all();
const originalRequests = $('準備 Kimi 請求').all();

for (let i = 0; i < kimiResponses.length; i++) {
  const item = kimiResponses[i];
  const original = originalRequests[i] ? originalRequests[i].json : {};

  const raw = item.json?.choices?.[0]?.message?.content || '';

  const cleaned = raw
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/gi, '')
    .trim();

  let parsed;
  try {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) throw new Error('No JSON found in response');
    parsed = JSON.parse(match[0]);
  } catch (e) {
    results.push({
      json: {
        error: true,
        message: e.message,
        raw,
        group_name: original._group_name || '',
        group_id: original._group_id || ''
      }
    });
    continue;
  }

  const now = new Date().toLocaleString('sv', {timeZone: 'Asia/Taipei'}).replace('T', ' ');

  results.push({
    json: {
      error: false,
      created_at: now,
      group_name: original._group_name || '',
      group_id: original._group_id || '',
      message_count: original._message_count || 0,
      summary: parsed.summary || '',
      topics: JSON.stringify(parsed.topics || []),
      notes: JSON.stringify(parsed.notes || []),
      people_count: parsed.people_count || 0,
      todos: parsed.todos || [],
      finance: parsed.finance || [],
      headcount: parsed.headcount || [],
      urls: original._urls || []
    }
  });
}

return results;
